solution.javascript:
import { test, expect } from '@playwright/test';

test('simple assertions', async ({ page }) => {
  await page.goto('https://demo.playwright.dev/todomvc');

  const input = page.getByPlaceholder('What needs to be done?');
  await expect(input).toBeVisible();

  await input.fill('Learn Playwright');
  await input.press('Enter');

  await expect(page.getByText('Learn Playwright')).toBeVisible();
  await expect(page).toHaveURL(/.*todomvc/);

  await expect(page.locator('.clear-completed')).not.toBeVisible();
});

